class Solution:
    def maximumLength(self, nums, k: int) -> int:
        # brute force O(n^2 k)
        n = len(nums)
        best = 1
        for r in range(k):
            dp = [1] * n
            for j in range(1, n):
                for i in range(j):
                    if (nums[i] + nums[j]) % k == r:
                        dp[j] = max(dp[j], dp[i] + 1)
            best = max(best, max(dp))
        return best

