class Solution:
    def maximumLength(self, nums, k: int) -> int:
        from collections import defaultdict
        # dp[r][v] = longest subseq ending with element % k == v, sum-remainder r
        dp = [[0] * k for _ in range(k)]
        ans = 1
        for x in nums:
            v = x % k
            for r in range(k):
                u = (r - v + k) % k
                dp[r][v] = max(dp[r][v], dp[r][u] + 1)
                ans = max(ans, dp[r][v])
        return ans

