var maximumLength = function(nums, k) {
    const dp = Array.from({length: k}, () => new Array(k).fill(0));
    let ans = 1;
    for (const x of nums) {
        const v = x % k;
        for (let r = 0; r < k; r++) {
            const u = ((r - v) % k + k) % k;
            dp[r][v] = Math.max(dp[r][v], dp[r][u] + 1);
            if (dp[r][v] > ans) ans = dp[r][v];
        }
    }
    return ans;
};
